const jobs = items.flatMap(i => i.json.details ?? [i.json]);

const failedJobs = jobs.filter(j =>
  j.status !== "success" ||
  (j.stderr && j.stderr.trim() !== "")
);

return [
  {
    json: {
      hasError: failedJobs.length > 0,
      failedJobs,
      total: jobs.length,
      failedCount: failedJobs.length
    }
  }
];

