const items = $input.all().map(i => i.json);

// détecter erreurs MSSQL (robuste)
const failed = items.filter(i =>
  (i.rowsAffected === 0 || i.rowsAffected === null || i.rowsAffected === undefined)
);

// build summary
return [
  {
    json: {
      hasError: failed.length > 0,
      status: failed.length > 0 ? "FAILED" : "SUCCESS",
      totalQueries: items.length,
      failedCount: failed.length,
      successfulCount: items.length - failed.length,
      failedJobs: failed,
      details: items
    }
  }
];
